return (async () => {
  const input = $input.first().json;
  const body = input.body || input;
  const env = $env || {};
  const https = require('https');
  const http = require('http');
  const { URL } = require('url');
  const now = new Date().toISOString();
  const creator = body.creator || {};
  const contact = creator.contact || {};
  const event = body.event || body.action || 'outreach_sent';
  const baseUrl = String(env.CHATWOOT_BASE_URL || 'http://localhost:3000').replace(/\/$/, '');
  const accountId = env.CHATWOOT_ACCOUNT_ID || '3';
  const token = env.CHATWOOT_API_TOKEN;

  function clean(value) { return String(value ?? '').trim(); }
  function compact(record) { return Object.fromEntries(Object.entries(record).filter(([, value]) => value !== undefined && value !== null && value !== '')); }
  function firstContact(data) {
    const payload = data?.payload;
    const list = Array.isArray(payload) ? payload : Array.isArray(payload?.contacts) ? payload.contacts : Array.isArray(data?.contacts) ? data.contacts : Array.isArray(data) ? data : [];
    const item = list[0] || payload?.contact || data?.contact;
    return item?.contact || item || null;
  }
  function requestJson(targetUrl, options = {}) {
    return new Promise((resolve, reject) => {
      const parsedUrl = new URL(targetUrl);
      const client = parsedUrl.protocol === 'https:' ? https : http;
      const requestBody = options.body ? String(options.body) : '';
      const request = client.request(parsedUrl, {
        method: options.method || 'GET',
        headers: {
          ...(options.headers || {}),
          ...(requestBody ? { 'Content-Length': Buffer.byteLength(requestBody) } : {}),
        },
      }, (response) => {
        let responseBody = '';
        response.setEncoding('utf8');
        response.on('data', (chunk) => { responseBody += chunk; });
        response.on('end', () => {
          let data = {};
          try { data = responseBody ? JSON.parse(responseBody) : {}; } catch { data = { raw: responseBody }; }
          resolve({ statusCode: response.statusCode || 0, data });
        });
      });
      request.on('error', reject);
      if (requestBody) request.write(requestBody);
      request.end();
    });
  }

  async function chatwoot(method, path, data) {
    const response = await requestJson(`${baseUrl}/api/v1/accounts/${accountId}${path}`, {
      method,
      headers: { 'Content-Type': 'application/json', api_access_token: token },
      body: data === undefined ? undefined : JSON.stringify(data),
    });
    const responseData = response.data || {};
    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw new Error(responseData?.message || responseData?.error || `Chatwoot ${method} ${path} failed with HTTP ${response.statusCode}`);
    }
    return responseData;
  }

  if (!token) {
    return [{ json: { ok: false, status: 'needs_chatwoot_config', source: 'chatwoot', message: 'CHATWOOT_API_TOKEN is not configured in n8n.', updatedAt: now } }];
  }

  const handle = clean(creator.handle).replace(/^@/, '');
  const name = clean(creator.displayName) || handle || 'Creator lead';
  const email = clean(contact.email);
  const identifier = clean(creator.id || creator.rawId || handle || email);
  const query = email || identifier || handle || name;
  if (!query && !identifier) {
    return [{ json: { ok: false, status: 'needs_creator_identity', source: 'chatwoot', message: 'Creator identity is missing.', updatedAt: now } }];
  }

  let contactRecord = null;
  try {
    const searchResult = await chatwoot('GET', `/contacts/search?q=${encodeURIComponent(query || identifier)}`);
    contactRecord = firstContact(searchResult);
  } catch {}

  if (!contactRecord?.id) {
    const createResult = await chatwoot('POST', '/contacts', compact({
      name,
      email: email || undefined,
      identifier,
      custom_attributes: compact({
        creator_id: creator.id,
        tiktok_handle: handle,
        tiktok_profile_url: creator.profileUrl,
        creator_source: creator.source,
      }),
    }));
    contactRecord = firstContact(createResult);
  }

  if (!contactRecord?.id) {
    throw new Error('Chatwoot did not return a contact id.');
  }

  const labels = ['creator-outreach'];
  if (event === 'outreach_sent') labels.push('creator-contacted');
  if (event === 'creator_replied') labels.push('creator-replied');
  if (event === 'sample_requested' || body.outreach?.crmStatus === 'sample_pending') labels.push('sample-pending');
  if (body.channel) labels.push(`channel-${body.channel}`);
  const nextStep = event === 'sample_requested' ? 'sample_followup' : event === 'creator_replied' ? 'reply_review' : 'wait_for_reply';

  await chatwoot('PATCH', `/contacts/${contactRecord.id}`, {
    custom_attributes: compact({
      creator_id: creator.id,
      tiktok_handle: handle,
      tiktok_profile_url: creator.profileUrl,
      outreach_status: body.outreach?.status || event,
      outreach_queue_id: body.queueId || body.outreach?.queueId,
      outreach_sent_at: body.outreach?.sentAt,
      next_step: nextStep,
      sample_status: labels.includes('sample-pending') ? 'sample_pending' : undefined,
      last_creator_event_at: now,
    }),
  });
  await chatwoot('POST', `/contacts/${contactRecord.id}/labels`, { labels });

  const noteLines = [
    `Creator outreach event: ${event}`,
    handle ? `TikTok: @${handle}` : '',
    creator.profileUrl ? `Profile: ${creator.profileUrl}` : '',
    body.channel ? `Channel: ${body.channel}` : '',
    body.outreach?.status ? `Outreach status: ${body.outreach.status}` : '',
    body.message?.subject ? `Subject: ${body.message.subject}` : '',
    body.message?.draft ? `Draft: ${body.message.draft}` : '',
    body.reply?.content ? `Reply: ${body.reply.content}` : '',
    `Next step: ${nextStep}`,
  ].filter(Boolean).join('\n');
  try {
    await chatwoot('POST', `/contacts/${contactRecord.id}/notes`, { note: { content: noteLines } });
  } catch {
    await chatwoot('POST', `/contacts/${contactRecord.id}/notes`, { content: noteLines });
  }

  let assignmentStatus = 'no_conversation';
  const conversationId = body.conversationId || body.conversation?.id;
  if (conversationId && env.CHATWOOT_CREATOR_ASSIGNEE_ID) {
    await chatwoot('POST', `/conversations/${conversationId}/assignments`, { assignee_id: Number(env.CHATWOOT_CREATOR_ASSIGNEE_ID) });
    assignmentStatus = 'assigned';
  }

  return [{ json: { ok: true, status: 'chatwoot_synced', source: 'chatwoot', contactId: contactRecord.id, labels, nextStep, assignmentStatus, updatedAt: now, chatwoot: { status: 'chatwoot_synced', contactId: contactRecord.id, labels, nextStep, assignmentStatus } } }];
})().catch((error) => [{ json: { ok: false, status: 'chatwoot_failed', source: 'chatwoot', message: error instanceof Error ? error.message : 'Chatwoot sync failed', updatedAt: new Date().toISOString() } }]);
